const item = $input.first().json;

const clean = (item.bodyText || '')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 4000);

return [{
  json: {
    title: (item.title || '').trim(),
    metaDescription: (item.metaDescription || '').trim(),
    homepageText: clean
  }
}];

const baseUrl = $('When Called by Orchestrator').first().json.website_url;
const html = $('Scrape Homepage').first().json.data || '';
const prev = $input.first().json;

const hrefRegex = /href=["']([^"'#]+)["']/gi;
const keywords = ['about', 'service', 'contact'];
const origin = new URL(baseUrl).origin;
const found = new Set();
let m;
while ((m = hrefRegex.exec(html)) !== null) {
  const href = m[1];
  if (!keywords.some((k) => href.toLowerCase().includes(k))) continue;
  try {
    const abs = new URL(href, baseUrl).toString();
    if (new URL(abs).origin === origin) found.add(abs);
  } catch (e) {
    // malformed href, skip
  }
}

return [{
  json: {
    ...prev,
    internalLinks: Array.from(found).slice(0, 2)
  }
}];

const prev = $input.first().json;
const links = prev.internalLinks || [];

const stripHtml = (html) => html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const extraPagesText = [];
for (const url of links) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url,
      timeout: 10000,
      returnFullResponse: true
    });
    const text = stripHtml(String(res.body || ''));
    if (text) extraPagesText.push(text.slice(0, 1500));
  } catch (e) {
    // best-effort enrichment, skip failed page
  }
}

return [{
  json: {
    ...prev,
    extraPagesText
  }
}];

const d = $input.first().json;

const parts = [d.homepageText || '', ...(d.extraPagesText || [])];
const aggregatedContent = parts
  .join(' \n\n ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 6000);

const businessNameGuess = (d.title || '')
  .split(/[-|\u2013]/)[0]
  .trim() || 'this business';

return [{
  json: {
    businessNameGuess,
    metaDescription: d.metaDescription || '',
    aggregatedContent
  }
}];

const res = $input.first().json;
const raw = res && res.choices && res.choices[0] && res.choices[0].message
  ? res.choices[0].message.content
  : undefined;

let spec;
try {
  spec = JSON.parse(raw);
} catch (e) {
  throw new Error('OpenAI returned invalid JSON for site spec: ' + String(raw).slice(0, 300));
}

const required = ['businessName', 'tagline', 'colorPalette', 'sections'];
const missing = required.filter((k) => !(k in spec));
if (missing.length) {
  throw new Error('Site spec missing required fields: ' + missing.join(', '));
}
if (!Array.isArray(spec.sections) || spec.sections.length === 0) {
  throw new Error('Site spec has no sections');
}

return [{ json: { spec } }];

const spec = $input.first().json.spec;
const contactEmail = $('When Called by Orchestrator').first().json.client_email || '';

const palette = Object.assign({ primary: '#4f46e5', secondary: '#0ea5e9', accent: '#f59e0b', background: '#ffffff', text: '#111827' }, spec.colorPalette || {});

const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const renderSection = (s) => {
  const heading = esc(s.heading);
  const body = esc(s.body);
  const items = s.items || [];
  if (s.type === 'hero') {
    return `<section id='hero' class='min-h-[80vh] flex flex-col items-center justify-center text-center px-6'><h1 class='text-4xl md:text-6xl font-extrabold mb-4' style='color:var(--color-primary)'>${heading}</h1><p class='text-lg md:text-2xl max-w-2xl mb-8'>${body}</p><a href='#contact' class='px-8 py-3 rounded-full font-semibold text-white' style='background:var(--color-primary)'>Get in touch</a></section>`;
  }
  if (s.type === 'services') {
    const cards = items.map((it) => `<div class='p-6 rounded-2xl shadow-sm border' style='border-color:var(--color-secondary)'>${esc(it)}</div>`).join('');
    return `<section id='services' class='py-20 px-6'><h2 class='text-3xl font-bold text-center mb-4' style='color:var(--color-primary)'>${heading}</h2><p class='text-center max-w-2xl mx-auto mb-10 opacity-80'>${body}</p><div class='grid gap-6 md:grid-cols-3 max-w-5xl mx-auto'>${cards}</div></section>`;
  }
  if (s.type === 'testimonials') {
    const quotes = items.map((it) => `<blockquote class='p-6 rounded-2xl bg-white/10'>${esc(it)}<footer class='mt-4 text-sm opacity-80'>Verified client</footer></blockquote>`).join('');
    return `<section id='testimonials' class='py-20 px-6' style='background:var(--color-secondary);color:#fff'><h2 class='text-3xl font-bold text-center mb-10'>${heading}</h2><div class='grid gap-6 md:grid-cols-3 max-w-5xl mx-auto'>${quotes}</div></section>`;
  }
  if (s.type === 'gallery') {
    const tiles = items.map((it) => `<div class='aspect-video rounded-xl flex items-center justify-center text-white font-medium' style='background:var(--color-accent)'>${esc(it)}</div>`).join('');
    return `<section id='gallery' class='py-20 px-6'><h2 class='text-3xl font-bold text-center mb-10' style='color:var(--color-primary)'>${heading}</h2><div class='grid gap-4 md:grid-cols-3 max-w-5xl mx-auto'>${tiles}</div></section>`;
  }
  if (s.type === 'contact') {
    return `<section id='contact' class='py-20 px-6 text-center'><h2 class='text-3xl font-bold mb-4' style='color:var(--color-primary)'>${heading}</h2><p class='max-w-xl mx-auto mb-6 opacity-80'>${body}</p><a href='mailto:${esc(contactEmail)}' class='px-8 py-3 rounded-full font-semibold text-white' style='background:var(--color-primary)'>${esc(contactEmail)}</a></section>`;
  }
  const list = items.length ? `<ul class='mt-6 space-y-2 text-left max-w-md mx-auto'>${items.map((it) => `<li>${esc(it)}</li>`).join('')}</ul>` : '';
  return `<section class='py-20 px-6 max-w-3xl mx-auto text-center'><h2 class='text-3xl font-bold mb-4' style='color:var(--color-primary)'>${heading}</h2><p class='opacity-80'>${body}</p>${list}</section>`;
};

const sectionsHtml = (spec.sections || []).map(renderSection).join('\n');
const year = new Date().getFullYear();

const html = `<!DOCTYPE html>\n<html lang='en'>\n<head>\n<meta charset='UTF-8' />\n<meta name='viewport' content='width=device-width, initial-scale=1.0' />\n<title>${esc(spec.businessName)}</title>\n<meta name='description' content='${esc(spec.seoDescription || spec.tagline || '')}' />\n<script src='https://cdn.tailwindcss.com'></script>\n<link rel='preconnect' href='https://fonts.googleapis.com'>\n<link href='https://fonts.googleapis.com/css2?family=Inter:wght@400;600;800&display=swap' rel='stylesheet'>\n<link rel='stylesheet' href='style.css'>\n</head>\n<body class='antialiased'>\n<nav class='flex items-center justify-between px-6 py-4 sticky top-0 z-10 backdrop-blur bg-white/70'>\n<span class='font-extrabold text-lg' style='color:var(--color-primary)'>${esc(spec.businessName)}</span>\n<span class='hidden md:block text-sm opacity-70'>${esc(spec.tagline || '')}</span>\n</nav>\n${sectionsHtml}\n<footer class='text-center py-8 text-sm opacity-60'>&copy; ${year} ${esc(spec.businessName)}. Site generated automatically.</footer>\n</body>\n</html>`;

return [{ json: { businessName: spec.businessName, spec, palette, files: [ { path: 'index.html', content: html } ] } }];

const prev = $input.first().json;
const p = prev.palette;

const css = `:root{--color-primary:${p.primary};--color-secondary:${p.secondary};--color-accent:${p.accent};--color-background:${p.background};--color-text:${p.text};}\nbody{font-family:'Inter',system-ui,sans-serif;background:var(--color-background);color:var(--color-text);}\na{transition:opacity .2s ease;}\na:hover{opacity:.85;}\n::selection{background:var(--color-accent);color:#fff;}`;

return [{ json: { ...prev, files: [...prev.files, { path: 'style.css', content: css }] } }];

const prev = $input.first().json;
const spec = prev.spec;
const today = new Date().toISOString().slice(0, 10);

const readme = `# ${spec.businessName}

${spec.tagline || ''}

This static site was automatically generated on ${today} as a redesign preview by an automated lead-generation pipeline.

## Files

- \`index.html\` — the site
- \`style.css\` — palette and base styles

Hosted via GitHub Pages. No build step required — edit the HTML/CSS directly.`;

return [{ json: { ...prev, files: [...prev.files, { path: 'README.md', content: readme }] } }];

const prev = $input.first().json;
const rowNumber = $('When Called by Orchestrator').first().json.row_number;

const slug = (prev.businessName || 'site')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 80) || 'site';

const repoName = `${slug}-lead-${rowNumber}`;

return [{ json: { ...prev, repoName } }];

const shaResp = $json;
const orig = $('Split Out Files').item.json;

let sha;
if (shaResp.statusCode === 200 && shaResp.data && shaResp.data.sha) {
  sha = shaResp.data.sha;
}

return {
  json: {
    ...orig,
    contentBase64: Buffer.from(orig.content, 'utf8').toString('base64'),
    sha
  }
};

const data = $('Compute Repo Name').first().json;
const owner = 'AhmedIrfan7';
const liveUrl = `https://${owner}.github.io/${data.repoName}/`;

return [{ json: { ...data, liveUrl } }];

const data = $input.first().json;
const rowNumber = $('When Called by Orchestrator').first().json.row_number;

return [{
  json: {
    success: true,
    rowNumber,
    repoName: data.repoName,
    liveUrl: data.liveUrl,
    businessName: data.businessName
  }
}];
